import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def test_padded_and_plain_codes_remain_distinct_and_lookup_exactly():
    database = sqlite3.connect(":memory:")
    database.executescript(
        (ROOT / "sql" / "schema.sql").read_text(encoding="utf-8")
    )
    try:
        database.executemany(
            "INSERT INTO catalog_items(id, vendor_code, description) VALUES (?, ?, ?)",
            [(1, "0012", "Padded fuse"), (2, "12", "Plain fuse")],
        )
    except sqlite3.IntegrityError as exc:
        raise AssertionError("distinct vendor codes collided during import") from exc

    lookup = (ROOT / "sql" / "item_lookup.sql").read_text(
        encoding="utf-8"
    )
    rows = database.execute(lookup, {"vendor_code": "0012"}).fetchall()

    assert rows == [(1, "0012", "Padded fuse")]
